# Resolve directory of the script
my $script_path = abs_path($0);
my $script_dir  = dirname($script_path);

# Move three levels up
my $target_dir  = abs_path(File::Spec->catdir($script_dir, '..', '..', '..'));

# Ensure directory exists
my $sm_run_dir = File::Spec->catdir($target_dir, '_testing', 'sm_worker');
make_path($sm_run_dir, { mode => 0777 });

# Path to debug file
my $debug_file = File::Spec->catfile($sm_run_dir, 'perl_param.debug');

# Create or update debug file
open(my $fh, '>', $debug_file) or die "Cannot open $debug_file: $!";
print $fh (defined $ARGV[1] ? $ARGV[1] : "");
close $fh;

# Set permissions recursively
my $test_dir = File::Spec->catdir($target_dir, '_testing');
system("chmod -R 777 '$test_dir'") == 0
    or die "Failed to chmod directories under $test_dir: $?";
